  ('locality-d0d1b9a2-moex-00408', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司採用目標成本制，為因應市場之競爭，擬將產品之售價降為$100，合理之利潤為售價 之20%，固定成本為$40,000元。下列敘述何者錯誤？', '["長期而言，企業必須要回收其全部的成本", "當競爭環境激烈時，目標成本制較少被使用", "若甲公司之銷售量為2,000單位，則目標單位變動成本為$60", "若甲公司之銷售量為4,000單位，則目標單位變動成本為$70"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "2b0bca06b571", "answer_pdf_sha1": "383f703f9d9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00409', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-111-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司目前生產30,000單位，占可用產能的2/3，產品價格為$14，單位固定成本為$2，變動 成本為每單位$6。今有乙公司對甲公司下一次性訂單 8,000 單位，每單位購價$8，甲公司須 負擔$2,000之產品運費，市場價格不受乙公司訂單及其他因素之影響。有關甲公司接受乙公 司訂單之敘述，下列何者正確？', '["不影響利潤", "減少利潤$2,000", "增加利潤$14,000", "增加利潤$16,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:08+00:00", "source_pdf_sha1": "2b0bca06b571", "answer_pdf_sha1": "383f703f9d9c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "315", "s": "1505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
